function LogoItem({ name, icon }: { name: string; icon: React.ReactNode }) {
	return (
		<div className="flex items-center gap-2 px-5 shrink-0 text-foreground/60 dark:text-foreground/40">
			<span className="shrink-0">{icon}</span>
			{name && (
				<span className="text-xs font-medium whitespace-nowrap tracking-wide">
					{name}
				</span>
			)}
		</div>
	);
}

export function TrustedBy() {
	return (
		<div className="space-y-3">
			{/* <p className="text-[11px] uppercase tracking-[0.15em] text-foreground/50 dark:text-foreground/30 font-medium">
				Trusted by
			</p> */}
			<div className="relative overflow-hidden">
				{/* Fade masks on left and right */}
				<div
					className="pointer-events-none absolute inset-0 z-10"
					style={{
						maskImage:
							"linear-gradient(to right, transparent, black 15%, black 85%, transparent)",
						WebkitMaskImage:
							"linear-gradient(to right, transparent, black 15%, black 85%, transparent)",
					}}
				>
					<div className="flex animate-logo-marquee w-fit">
						{/* Repeat 2 times for seamless loop - translates exactly 50% */}
						{[0, 1].map((setIdx) => (
							<div key={setIdx} className="flex shrink-0">
								{logos.map((logo, i) => (
									<LogoItem
										key={`${setIdx}-${i}-${logo.name}`}
										name={logo.name}
										icon={logo.icon}
									/>
								))}
							</div>
						))}
					</div>
				</div>
				{/* Invisible spacer to maintain height */}
				<div className="flex invisible" aria-hidden="true">
					{logos.slice(0, 1).map((logo, i) => (
						<LogoItem key={`spacer-${i}`} name={logo.name} icon={logo.icon} />
					))}
				</div>
			</div>
		</div>
	);
}
